-- Create exercises table if not exists
create table if not exists public.exercises (
  id uuid default uuid_generate_v4() primary key,
  name text not null,
  category text,
  subcategory text,
  video_url text,
  description text,
  type text check (type in ('Compound', 'Isolation')),
  muscle_groups text[] default '{}'::text[],
  secondary_muscles text[] default '{}'::text[],
  tools text[] default '{}'::text[],
  difficulty_level text check (difficulty_level in ('Beginner', 'Intermediate', 'Advanced')),
  icon text default 'fitness_center',
  created_at timestamp with time zone default timezone('utc'::text, now())
);

-- Enable RLS
alter table public.exercises enable row level security;

-- Policies
create policy "Anyone can view exercises" on public.exercises for select using (true);
create policy "Managers can manage exercises" on public.exercises for all using (
  exists (select 1 from public.users where id = auth.uid() and role = 'MANAGER')
);

